export const MIX_TEMEL = Object.entries(DECK_CARDS)
  .filter(([slug]) => ['anatomy','physio','biochem','micro','patho','pharma'].includes(slug))
  .flatMap(([,cards]) => cards)

export const MIX_KLINIK = Object.entries(DECK_CARDS)
  .filter(([slug]) => ['prosthetic','surgery','ortho','endo','resto','pedo','radio','perio'].includes(slug))
  .flatMap(([,cards]) => cards)

export const MIX_ALL = [...MIX_TEMEL, ...MIX_KLINIK]

// ── SM-2 SRS Algoritması ─────────────────────────────────────
export function calcSM2(card, confidence) {
  let { interval = 1, easeFactor = 2.5 } = card
  if (confidence >= 3) {
    if (interval === 1) interval = 6
    else interval = Math.round(interval * easeFactor)
    easeFactor = Math.max(1.3, easeFactor + 0.1 - (5 - confidence) * 0.08)
  } else {
    interval = 1
  }
  const nextReview = new Date(Date.now() + interval * 86400000)
  return { interval, easeFactor, nextReview }
}

